	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Validate orderBy against a whitelist to prevent SQL injection.
	// SQL drivers do not support parameter placeholders for identifiers like column names.
	var sanitizedOrderBy string
	switch strings.ToLower(orderBy) {
	case "id":
