	case "name":
		sanitizedOrderBy = "name"
	case "price":
		sanitizedOrderBy = "price"
	default:
		return nil, errors.New("invalid order by column")
	}

	// Normalize and validate sortDir
	sortDir = strings.ToUpper(sortDir)
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("invalid sort direction")
	}

	// Safely construct the query using the validated identifiers
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", sanitizedOrderBy, sortDir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	// Check for errors encountered during iteration
	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

